class CustomInstallCommand(install):
    """Custom install command that runs post-installation tasks."""

    description = "Install the package and run post-installation setup tasks"
    user_options = install.user_options + [
        ("skip-resource-download", None, "Skip downloading additional resources"),
        ("skip-env-setup", None, "Skip environment variable setup"),
    ]

    def initialize_options(self):
        super().initialize_options()
        self.skip_resource_download = False
        self.skip_env_setup = False

    def finalize_options(self):
        super().finalize_options()

    def run(self):
        # Run the standard install first
        super().run()

        # Then run custom post-installation tasks
        print("\n")
        print(f"[Setup] Starting custom post-installation for {PACKAGE_NAME}...")

        config_dir = create_config_directories()

        if not self.skip_resource_download:
            download_resources(config_dir)
        else:
            print("[Setup] Skipping resource download (--skip-resource-download)")

        generate_default_config(config_dir)

        if not self.skip_env_setup:
            setup_environment_variables(config_dir)
        else:
            print("[Setup] Skipping environment setup (--skip-env-setup)")

        version_file = config_dir / ".version"
        with open(version_file, "w") as f:
            f.write(PACKAGE_VERSION)

        print(f"[Setup] Installation of {PACKAGE_NAME} completed successfully!")


