class CleanConfigCommand(install):
    """Custom command to clean up configuration directories and environment variables."""

    description = "Remove all configuration directories and environment variables"
    user_options = []

    def initialize_options(self):
        pass

    def finalize_options(self):
        pass

    def run(self):
        config_dir = get_config_dir()
        if config_dir.exists():
            print(f"[Setup] Removing configuration directory: {config_dir}")
            shutil.rmtree(config_dir)
            print("[Setup] Configuration directory removed.")
        else:
            print("[Setup] No configuration directory found.")

        # Clean environment variables
        for var_name in ENV_VARS:
            if var_name in os.environ:
                del os.environ[var_name]
                print(f"[Setup] Removed environment variable: {var_name}")

        # Clean shell profile entries
        home = Path.home()
        marker_start = f"# >>> {PACKAGE_NAME} >>>"
        marker_end = f"# <<< {PACKAGE_NAME} <<<"

        for profile_name in [".bashrc", ".zshrc", ".profile"]:
            profile = home / profile_name
            if profile.exists():
                content = profile.read_text()
                if marker_start in content:
                    start_idx = content.index(marker_start)
                    end_idx = content.index(marker_end) + len(marker_end)
                    new_content = content[:start_idx] + content[end_idx:]
                    new_content = new_content.strip() + "\n"
                    profile.write_text(new_content)
                    print(f"[Setup] Cleaned shell profile: {profile}")

        print("[Setup] Cleanup completed.")


